+fn normalize_in_place(vec: &mut [f32]) {
+    let norm_sq: f32 = vec.iter().map(|x| x * x).sum();
+    if norm_sq.is_finite() && norm_sq > f32::EPSILON {
+        let inv_norm = 1.0 / norm_sq.sqrt();
+        for x in vec {
+            *x *= inv_norm;
+        }
+    } else {
+        vec.fill(0.0);
+    }
+}
